1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	
16	type Item = { type: string };
17	type Step = { op: string; items: Item[] };
18	type Scenario = { steps: Step[] };
19	
20	const basePremiumForItem = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
21	
22	const countItemsOfType = (items: Item[], type: string): number =>
23	  items.filter((item) => item.type === type).length;
24	
25	const basePremiumForComponentType = (items: Item[], type: string): number => {
26	  const count = countItemsOfType(items, type);
27	  return count === COMPONENT_BLOCK_SIZE
28	    ? COMPONENT_BLOCK_PRICE
29	    : count * (BASE_PREMIUM_BY_TYPE[type] ?? 0);
30	};
31	
32	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
33	
34	const basePremiumFor = (items: Item[]): number => {
35	  const componentsTotal = COMPONENT_TYPES.reduce(
36	    (sum, type) => sum + basePremiumForComponentType(items, type),
37	    0,
38	  );
39	  const nonComponentsTotal = items
40	    .filter((item) => !isComponent(item))
41	    .reduce((sum, item) => sum + basePremiumForItem(item), 0);
42	  return componentsTotal + nonComponentsTotal;
43	};
44	
45	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
46	  const { steps } = input as Scenario;
47	  const premium = basePremiumFor(steps[0].items) + PROCESSING_FEE;
48	  return { results: [{ premium }] };
49	};
