type Item = { type: string; cursed?: boolean };
type Step = { op: string; items: Item[] };
type Scenario = { steps: Step[] };

const basePremiumForItem = (item: Item): number => {
  const base = BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
  return item.cursed ? base * 1.5 : base;
};
